function ok = fTxtOutV01(nam,nmb,ttl,dat,varargin)%% save data in a spread sheet (old style, not cell)%% ok = fTxtOutV01(nam,nmb,ttl,dat,varargin)%% nam: file path% nmb: number of data% ttl: cell with title for output% dat: data for output, [number_of_shot x number_of_data]% digits: number of digits to be saved, optional%%% Written by Kei Nakamura% 2010/9/19 ver.1: created%% Used in% bellaFrogPhaseFitV07,%%% mainif nargin==4    digits = 5; % default 5else    digits = varargin{end};end%escC = ['%.',num2str(digits),'f'];escC = ['%.',num2str(digits),'e'];ss = fEscMakerV01('%s',nmb);ff = fEscMakerV01(escC,nmb);fid=fopen(nam,'w');fprintf(fid,ss,ttl{1:nmb});fprintf(fid,ff,dat');ok = fclose(fid);
